<?php namespace App\Repositories\Admission;use App\Repositories\BaseRepository;use App\Models\Admission\MeritList;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class MeritListRepository extends BaseRepository{    public function __construct(MeritList $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByExam(int $examId): Collection    {        return $this->findByField('entrance_exam_id', $examId);    }    public function findByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function findByRankRange(int $minRank, int $maxRank): Collection    {        return $this->query()->whereBetween('rank', [$minRank, $maxRank])->get();    }    public function getTopRankers(int $limit = 10): Collection    {        return $this->query()->orderBy('rank', 'asc')->limit($limit)->get();    }    public function getConfirmedAdmissions(): Collection    {        return $this->query()->where('is_confirmed', true)->get();    }    public function getPendingConfirmations(): Collection    {        return $this->query()->where('is_confirmed', false)->get();    }}